import { useState, useEffect } from "react";

const C = {
  bg: "#000000", surface: "#0F0F0F", card: "#161616", border: "#222",
  text: "#FFF", sub: "#D0D0D0", dim: "#BABABA", red: "#FF0000",
  redGlow: "rgba(255,0,0,0.12)", redBorder: "rgba(255,0,0,0.35)",
  green: "#34D399", greenDim: "rgba(52,211,153,0.12)",
  yellow: "#FBBF24", yellowDim: "rgba(251,191,36,0.12)",
  orange: "#FB923C", orangeDim: "rgba(251,146,60,0.12)",
};
const F = {
  serif: "'Instrument Serif', Georgia, serif",
  sans: "'DM Sans', system-ui, sans-serif",
  mono: "'DM Mono', 'SF Mono', monospace",
};

// ── Q-Trees ──
const trees = {
  "Tech / Product": {
    icon: "💻",
    detected: "You watched 23 tech reviews this month",
    questions: [
      { q: "What's your take right now?", opts: ["Something's overhyped", "Something's underrated", "I have a prediction", "I want to break down what actually shipped"] },
      { q: "What specifically?", opts: ["A product launch everyone's talking about", "An AI claim that doesn't hold up", "A design decision nobody noticed", "A feature that quietly changed everything"] },
      { q: "Who needs to hear this?", opts: ["Other builders and PMs", "People outside tech", "Anyone who almost bought into the hype", "My future self in 6 months"] },
      { q: "How do you want to say it?", opts: ["Calm breakdown with receipts", "Rant with a point", "Quick hot take, under 30 seconds", "Side-by-side comparison"] },
    ],
    generic: "T-Rex fails to make a bed because his arms are too short",
    build: (a) => `${a[3]}. ${a[1]}. Framed as "${a[0]?.toLowerCase()}." For ${a[2]?.toLowerCase()}.`,
  },
  "F1 Racing": {
    icon: "🏎️",
    detected: "You watched 14 F1 videos this week",
    questions: [
      { q: "What's on your mind from the race weekend?", opts: ["A strategy call nobody's questioning", "A driver who deserves more credit", "Something the broadcast missed", "A take I know will be controversial"] },
      { q: "What's the angle?", opts: ["The data says something different than the narrative", "Everyone's blaming the wrong person", "This is going to matter in 3 races", "I just need to get this off my chest"] },
      { q: "How deep do you want to go?", opts: ["30-second hot take", "1-minute breakdown with context", "Full analytical deep dive", "Emotional fan reaction, raw"] },
      { q: "What's the energy?", opts: ["Serious pundit mode", "Passionate fan energy", "Dry comedy", "Educational, explaining it to a new fan"] },
    ],
    generic: "Make me a race car driver winning a Grand Prix",
    build: (a) => `${a[2]}. ${a[0]}. Angle: "${a[1]?.toLowerCase()}." Energy: ${a[3]?.toLowerCase()}.`,
  },
  "Music": {
    icon: "🎵",
    detected: "You listened to 8 music breakdowns recently",
    questions: [
      { q: "What kind of music moment is this?", opts: ["A song I can't stop thinking about", "Something I want to create or remix", "A take on the music industry", "Breaking down why something works"] },
      { q: "What's the hook?", opts: ["An opinion most people would disagree with", "A hidden detail nobody caught", "A comparison that changes how you hear it", "Something I learned by trying to recreate it"] },
      { q: "Genre world?", opts: ["Pop / R&B", "Rock / Alt / Indie", "Hip-hop / Rap", "Electronic / Experimental"] },
      { q: "Format?", opts: ["Quick reaction, under 30 seconds", "Audio breakdown with examples", "Performance or cover clip", "Commentary essay"] },
    ],
    generic: "Hamster scratching vinyl record",
    build: (a) => `${a[3]}. ${a[0]} in ${a[2]?.toLowerCase()}. Hook: "${a[1]?.toLowerCase()}."`,
  },
};

// ── Timeline ──
const tl = [
  { id: "T0", l: "Trigger", s: "partial", d: "Trends tab surfaces trending content in-feed, but doesn't bridge viewing to creation intent" },
  { id: "T1", l: "Intent", s: "missing", d: "\"I want to make something but don't know what specifically.\" No dedicated surface exists" },
  { id: "T2", l: "Prompt", s: "shipped", d: "Create video flow: showcase prompt cards + blank text field" },
  { id: "T3", l: "Generate", s: "shipped", d: "Veo 3 / Dream Screen / Imagen 3 generation engine" },
  { id: "T4", l: "Output", s: "partial", d: "Preview exists, but no recovery when generation fails or drifts from intent" },
  { id: "T5", l: "Edit", s: "shipped", d: "Edit with AI. Restructures footage you already have" },
  { id: "T6", l: "Analytics", s: "shipped", d: "Ask Studio. Post-publish channel insights" },
  { id: "T7", l: "Re-create", s: "partial", d: "No creator self-signal connecting past creations to next prompt" },
];

// ── Screenshot Data (resized base64 for embedding) ──
const SS_PROMPTS = "data:image/jpeg;base64,";
const SS_BLANK = "data:image/jpeg;base64,";
const SS_CREATING = "data:image/jpeg;base64,";
const SS_ERROR = "data:image/jpeg;base64,";

// ── Shared ──
const Mono = ({children, color, style}) => (
  <span style={{ fontFamily: F.mono, fontSize: "11px", letterSpacing: "0.12em", textTransform: "uppercase", color: color || C.red, ...style }}>{children}</span>
);
const H2 = ({children}) => (
  <h2 style={{ fontFamily: F.serif, fontSize: "clamp(30px,5vw,52px)", color: C.text, lineHeight: 1.12, fontWeight: 400, margin: "0 0 20px" }}>{children}</h2>
);
const Sub = ({children, style}) => (
  <p style={{ fontFamily: F.sans, fontSize: "16px", color: C.sub, lineHeight: 1.7, maxWidth: "580px", margin: "0 0 48px", ...style }}>{children}</p>
);
const Pill = ({children, color, bg}) => (
  <span style={{ fontFamily: F.mono, fontSize: "9px", letterSpacing: "0.08em", color, background: bg, padding: "3px 8px", borderRadius: "3px", textTransform: "uppercase", fontWeight: 500 }}>{children}</span>
);

// ── Nav ──
function Nav() {
  const [s, setS] = useState(false);
  useEffect(() => { const f = () => setS(window.scrollY > 50); window.addEventListener("scroll", f); document.title = "The Missing Minute · YouTube GenAI Creation pitch by Sid Sundaram"; return () => window.removeEventListener("scroll", f); }, []);
  return (
    <nav style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 100, padding: "14px 28px", display: "flex", justifyContent: "space-between", alignItems: "center", background: s ? "rgba(0,0,0,0.88)" : "transparent", backdropFilter: s ? "blur(16px)" : "none", borderBottom: `1px solid ${s ? C.border : "transparent"}`, transition: "all 0.3s" }}>
      <Mono color={C.sub}>The Missing Minute</Mono>
      <Mono color={C.dim}>YouTube GenAI Creation · PM Intern Pitch</Mono>
    </nav>
  );
}

// ── Hero ──
function Hero() {
  const [v, setV] = useState(false);
  useEffect(() => { setTimeout(() => setV(true), 150); }, []);
  return (
    <section style={{ minHeight: "100vh", display: "flex", flexDirection: "column", justifyContent: "center", padding: "80px 40px 40px", maxWidth: "1100px", margin: "0 auto" }}>
      <div style={{ opacity: v?1:0, transform: v?"none":"translateY(24px)", transition: "all 0.7s ease" }}>
        <Mono>The unowned slot in YouTube's creation journey</Mono>
        <h1 style={{ fontFamily: F.serif, fontSize: "clamp(46px,7vw,76px)", color: C.text, lineHeight: 1.02, fontWeight: 400, margin: "20px 0 24px" }}>
          The Missing Minute
        </h1>
        <Sub>
          YouTube's GenAI roadmap improves every step of the creation journey. Better models, better editing, better post-production. But between{" "}
          <span style={{ color: C.text }}>"I want to make something"</span> and{" "}
          <span style={{ color: C.text }}>"here's my prompt,"</span>{" "}
          there's no surface at all. That's where intent dies before it becomes a video.
        </Sub>
      </div>
      <div style={{ opacity: v?1:0, transform: v?"none":"translateY(32px)", transition: "all 0.7s ease 0.25s" }}>
        <TimelineViz />
      </div>
      <div style={{ marginTop: "40px", textAlign: "center", opacity: 0.4, animation: "bounce 2s infinite" }}>
        <Mono color={C.dim}>↓ The evidence</Mono>
      </div>
    </section>
  );
}

function TimelineViz() {
  const [hover, setHover] = useState(null);
  return (
    <div style={{ display: "flex", alignItems: "stretch", gap: "3px", marginTop: "8px" }}>
      {tl.map((t, i) => {
        const miss = t.s === "missing";
        const part = t.s === "partial";
        const active = hover === i;
        return (
          <div key={t.id}
            onMouseEnter={() => setHover(i)} onMouseLeave={() => setHover(null)}
            onClick={() => {
              const map = { T1: "diagnosis", T2: "evidence", T4: "evidence", T5: "strategy", T6: "strategy", T7: "strategy" };
              const target = map[t.id];
              if (target) document.getElementById(target)?.scrollIntoView({ behavior: "smooth" });
            }}
            style={{
              flex: miss ? 2.2 : 1, padding: miss ? "20px 16px" : "14px 10px",
              background: miss ? C.redGlow : active ? C.card : "rgba(255,255,255,0.02)",
              border: `1px solid ${miss ? C.redBorder : active ? C.border : "rgba(255,255,255,0.04)"}`,
              borderRadius: "6px", cursor: "pointer", transition: "all 0.25s", position: "relative",
              ...(miss ? { boxShadow: "0 0 24px rgba(255,0,0,0.08)" } : {}),
            }}>
            <div style={{ fontFamily: F.mono, fontSize: "9px", color: miss ? C.red : part ? C.yellow : C.dim, letterSpacing: "0.1em", marginBottom: miss ? "8px" : "4px" }}>{t.id}</div>
            <div style={{ fontFamily: F.sans, fontSize: miss ? "14px" : "12px", fontWeight: miss ? 600 : 500, color: miss ? C.text : active ? C.sub : C.dim }}>{t.l}</div>
            {miss && (
              <div style={{ marginTop: "10px" }}>
                <Pill color={C.red} bg={C.redGlow}>★ No surface exists</Pill>
                <p style={{ fontFamily: F.sans, fontSize: "12px", color: C.sub, lineHeight: 1.5, marginTop: "10px" }}>
                  {t.d}
                </p>
              </div>
            )}
            {(active && !miss) && (
              <div style={{ marginTop: "6px" }}>
                <Pill color={t.s === "shipped" ? C.green : C.yellow} bg={t.s === "shipped" ? C.greenDim : C.yellowDim}>
                  {t.s === "shipped" ? "● Shipped" : "◇ Partial"}
                </Pill>
                <p style={{ fontFamily: F.sans, fontSize: "11px", color: C.dim, lineHeight: 1.4, marginTop: "6px" }}>
                  {t.d}
                </p>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ── Evidence ──
function Evidence() {
  return (
    <section id="evidence" style={{ padding: "100px 40px", maxWidth: "1100px", margin: "0 auto" }}>
      <Mono>The evidence</Mono>
      <H2>
        Every prompt assumes you already know what you want to make.
        <br /><span style={{ color: C.dim }}>None of them help you figure it out.</span>
      </H2>
      <Sub>
        I opened YouTube's Shorts text-to-video Create flow as a first-time creator.
        The experience offered two paths: pick from generic showcase prompts, or
        type into a blank field. Both assume a committed idea already exists. Neither
        helps form one.
      </Sub>

      <div className="grid-2" style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px", marginBottom: "48px" }}>
        <Card>
          <Pill color={C.dim} bg="rgba(255,255,255,0.04)">CURRENT: SHOWCASE PROMPTS</Pill>
          <h3 style={{ fontFamily: F.sans, fontSize: "17px", fontWeight: 600, color: C.text, margin: "16px 0 14px" }}>
            Pre-written ideas to pick from
          </h3>
          <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
            {["🦖 T-Rex fails to make a bed because his arms are too short", "🐙 Make me fight a giant octopus", "🐹 Hamster scratching vinyl record", "🐱 Cute, sad cat wrapped in a comfy blanket", "🐿️ Make me lose badly in chess against a squirrel"].map((p,i) => (
              <div key={i} style={{ fontFamily: F.sans, fontSize: "13px", color: C.sub, padding: "10px 12px", background: "rgba(255,255,255,0.03)", borderRadius: "8px", border: `1px solid rgba(255,255,255,0.05)` }}>{p}</div>
            ))}
          </div>
          <p style={{ fontFamily: F.sans, fontSize: "12px", color: C.dim, marginTop: "16px", lineHeight: 1.6 }}>
            Amusing. Identical for every user. No connection to what you watch,
            care about, or would actually post. The format is: here's a finished idea, take it or leave it.
          </p>
        </Card>

        <Card>
          <Pill color={C.dim} bg="rgba(255,255,255,0.04)">CURRENT: BLANK TEXT FIELD</Pill>
          <h3 style={{ fontFamily: F.sans, fontSize: "17px", fontWeight: 600, color: C.text, margin: "16px 0 14px" }}>
            "Describe your idea"
          </h3>
          <div style={{ background: "rgba(255,255,255,0.03)", borderRadius: "12px", border: `1px solid rgba(255,255,255,0.06)`, padding: "48px 20px", display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: "16px", minHeight: "220px" }}>
            <div style={{ width: "100%", padding: "14px 16px", borderRadius: "24px", background: "rgba(255,255,255,0.06)", border: `1px solid rgba(255,255,255,0.08)`, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <span style={{ fontFamily: F.sans, fontSize: "14px", color: C.dim }}>Describe your idea</span>
              <span style={{ fontSize: "18px", color: C.dim }}>→</span>
            </div>
            <span style={{ fontFamily: F.sans, fontSize: "12px", color: C.dim }}>The blank-page problem, inside a creation tool built to eliminate blank pages.</span>
          </div>
          <p style={{ fontFamily: F.sans, fontSize: "12px", color: C.dim, marginTop: "16px", lineHeight: 1.6 }}>
            GenAI was supposed to remove the skill barrier. But knowing what to type is itself
            a skill. The articulation gap moves, it doesn't disappear.
          </p>
        </Card>
      </div>

      {/* Friction strip */}
      <div className="grid-4" style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "12px" }}>
        {[
          { n: "1", t: "Generic prompts", d: "Same for every user", e: "🎭" },
          { n: "2", t: "Blank text field", d: "\"Describe your idea\"", e: "📝" },
          { n: "3", t: "Long generation", d: "10% progress bar, peak drop-off risk", e: "⏳" },
          { n: "4", t: "\"Something went wrong\"", d: "No recovery. One-and-done exit", e: "❌" },
        ].map(s => (
          <div key={s.n} style={{ padding: "20px 16px", background: C.card, border: `1px solid ${C.border}`, borderRadius: "8px" }}>
            <div style={{ fontFamily: F.mono, fontSize: "9px", color: C.dim, marginBottom: "10px", fontWeight: 600 }}>STEP {s.n}</div>
            <div style={{ fontSize: "20px", marginBottom: "8px" }}>{s.e}</div>
            <div style={{ fontFamily: F.sans, fontSize: "13px", fontWeight: 600, color: C.text, marginBottom: "4px" }}>{s.t}</div>
            <div style={{ fontFamily: F.sans, fontSize: "11px", color: C.dim, lineHeight: 1.5 }}>{s.d}</div>
          </div>
        ))}
      </div>

      {/* Actual screenshots from the live product */}
      <ScreenshotStrip />
    </section>
  );
}

function Card({children}) {
  return <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: "12px", padding: "28px" }}>{children}</div>;
}

function ScreenshotStrip() {
  const [open, setOpen] = useState(false);
  const shots = [
    { src: SS_PROMPTS, label: "Generic showcase prompts" },
    { src: SS_BLANK, label: "Blank text field + custom prompt" },
    { src: SS_CREATING, label: "Creating... 10%" },
    { src: SS_ERROR, label: "\"Something went wrong\"" },
  ];
  return (
    <div style={{ marginTop: "32px" }}>
      <button onClick={() => setOpen(!open)} style={{
        background: "none", border: `1px solid ${C.border}`, borderRadius: "8px",
        padding: "10px 16px", cursor: "pointer", fontFamily: F.mono, fontSize: "11px",
        color: C.sub, letterSpacing: "0.08em", fontWeight: 500,
      }}>
        {open ? "Hide" : "View"} actual screenshots from the live product {open ? "↑" : "↓"}
      </button>
      {open && (
        <div style={{ marginTop: "16px", display: "flex", gap: "12px", overflowX: "auto", paddingBottom: "8px" }}>
          {shots.map((s, i) => (
            <div key={i} style={{ flexShrink: 0, textAlign: "center" }}>
              <img src={s.src} alt={s.label} style={{ height: "280px", borderRadius: "12px", border: `1px solid ${C.border}` }} />
              <p style={{ fontFamily: F.mono, fontSize: "9px", color: C.dim, marginTop: "8px", maxWidth: "140px" }}>{s.label}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ── Diagnosis ──
function Diagnosis() {
  return (
    <section id="diagnosis" style={{ padding: "100px 40px", maxWidth: "1100px", margin: "0 auto" }}>
      <Mono>The diagnosis</Mono>
      <H2>
        GenAI fixed the skill problem.
        <br /><span style={{ color: C.dim }}>It left the articulation problem untouched.</span>
      </H2>
      <Sub>
        Veo 3, Dream Screen, and AI avatars mean you don't need editing skills to
        create. But the user at T1 already tapped Create. They have motivation. What
        they lack is a way to convert a vague impulse into a committed prompt.
        Current prompt cards try to motivate when the user actually needs to articulate.
      </Sub>

      {/* MAT cards */}
      <div className="grid-3" style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: "16px", marginBottom: "48px" }}>
        {[
          { l: "M", n: "Motivation", st: "PRESENT", sc: C.green, d: "The user tapped Create. Some motivation exists. But it's fragile. Generic prompts don't sustain it because they're disconnected from what the user actually cares about." },
          { l: "A", n: "Ability", st: "PARTIALLY FIXED", sc: C.yellow, d: "AI handles production. You type a sentence, you get a video. But knowing what to type is itself a skill. The mental effort of prompt-writing reintroduces the friction AI was supposed to remove." },
          { l: "T", n: "Trigger", st: "WRONG TYPE", sc: C.orange, d: "Prompt cards try to boost motivation (\"look at this fun idea!\"). But the user already has motivation. They need help articulating. The interaction should facilitate, not inspire." },
        ].map(m => (
          <Card key={m.l}>
            <div style={{ display: "flex", alignItems: "center", gap: "12px", marginBottom: "14px" }}>
              <span style={{ fontFamily: F.serif, fontSize: "36px", fontStyle: "italic", color: m.sc }}>{m.l}</span>
              <div>
                <div style={{ fontFamily: F.sans, fontSize: "15px", fontWeight: 600, color: C.text }}>{m.n}</div>
                <Pill color={m.sc} bg={m.sc === C.green ? C.greenDim : m.sc === C.yellow ? C.yellowDim : m.sc === C.orange ? C.orangeDim : C.redGlow}>{m.st}</Pill>
              </div>
            </div>
            <p style={{ fontFamily: F.sans, fontSize: "13px", color: C.sub, lineHeight: 1.65 }}>{m.d}</p>
          </Card>
        ))}
      </div>

      {/* Axis split */}
      <Card>
        <div className="axis-grid" style={{ display: "grid", gridTemplateColumns: "1fr 1px 1fr", gap: "28px" }}>
          <div>
            <Pill color={C.dim} bg="rgba(255,255,255,0.04)">CONTENT AXIS — WHERE YOUTUBE IS INVESTING</Pill>
            <h3 style={{ fontFamily: F.sans, fontSize: "16px", fontWeight: 600, color: C.text, margin: "14px 0 8px" }}>Improve WHAT gets suggested</h3>
            <p style={{ fontFamily: F.sans, fontSize: "13px", color: C.sub, lineHeight: 1.65 }}>
              Veo 3 and AI avatars improve the models. Inspiration Tab updates improve the prompt cards.
              Edit with AI improves post-creation. Every investment targets the
              content of the suggestion or the quality of the output.
            </p>
          </div>
          <div className="axis-divider" style={{ background: C.border }} />
          <div>
            <Pill color={C.red} bg={C.redGlow}>INTERACTION AXIS — UNOWNED</Pill>
            <h3 style={{ fontFamily: F.sans, fontSize: "16px", fontWeight: 600, color: C.text, margin: "14px 0 8px" }}>Change HOW the user gets to a prompt</h3>
            <p style={{ fontFamily: F.sans, fontSize: "13px", color: C.sub, lineHeight: 1.65 }}>
              Treat first-prompt formation as a clarification problem. Extract what
              the creator already knows through 30 seconds of tappable disambiguation,
              rather than pushing a suggestion. Personalization makes the wrong
              format work better. Disambiguation changes the format.
            </p>
          </div>
        </div>
      </Card>
    </section>
  );
}

// ── Shorts-style Demo ──
function Demo() {
  const [niche, setNiche] = useState(null);
  const [qIdx, setQIdx] = useState(0);
  const [ans, setAns] = useState([]);
  const [done, setDone] = useState(false);
  const [showCompare, setShowCompare] = useState(false);

  const tree = niche ? trees[niche] : null;
  const reset = () => { setNiche(null); setQIdx(0); setAns([]); setDone(false); setShowCompare(false); };
  const pick = (a) => {
    const next = [...ans, a];
    setAns(next);
    if (qIdx < tree.questions.length - 1) setQIdx(qIdx + 1);
    else { setDone(true); setTimeout(() => setShowCompare(true), 600); }
  };

  return (
    <section style={{ padding: "100px 40px", maxWidth: "1100px", margin: "0 auto" }}>
      <Mono>Interactive demo</Mono>
      <H2>
        Disambiguation in 30 seconds.
        <br /><span style={{ color: C.dim }}>Four taps. One prompt that's yours.</span>
      </H2>
      <Sub>
        Instead of choosing from generic showcase prompts or facing a blank text
        field, walk through four quick questions. Every answer narrows your intent.
        The final prompt is unique to you, because every word came from your choices.
      </Sub>

      <div className="demo-layout" style={{ display: "flex", gap: "32px", alignItems: "flex-start", justifyContent: "center" }}>
        {/* Phone mockup */}
        <div className="phone-mock" style={{
          width: "340px", minHeight: "640px", background: "#000",
          borderRadius: "36px", border: "3px solid #333",
          overflow: "hidden", position: "relative", flexShrink: 0,
          boxShadow: "0 20px 60px rgba(0,0,0,0.6)",
        }}>
          {/* Status bar */}
          <div style={{ padding: "12px 24px 8px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <span style={{ fontFamily: F.sans, fontSize: "13px", fontWeight: 600, color: C.text }}>1:07</span>
            <div style={{ display: "flex", gap: "5px", alignItems: "center" }}>
              <span style={{ fontSize: "11px", color: C.text }}>📶</span>
              <span style={{ fontSize: "11px", color: C.text }}>🔋</span>
            </div>
          </div>

          {/* Header */}
          <div style={{ padding: "8px 20px 12px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
              <span style={{ fontSize: "20px", color: C.text, cursor: "pointer" }} onClick={reset}>←</span>
              <span style={{ fontFamily: F.sans, fontSize: "16px", fontWeight: 700, color: C.text }}>Create video</span>
            </div>
            {niche && (
              <div style={{ width: "28px", height: "28px", borderRadius: "50%", background: "rgba(255,255,255,0.1)", display: "flex", alignItems: "center", justifyContent: "center" }}>
                <span style={{ fontSize: "14px" }}>✦</span>
              </div>
            )}
          </div>

          {/* Content area */}
          <div style={{ padding: "8px 16px", minHeight: "440px", display: "flex", flexDirection: "column" }}>
            {!niche && (
              <>
                <p style={{ fontFamily: F.mono, fontSize: "9px", color: C.dim, letterSpacing: "0.1em", marginBottom: "6px", textTransform: "uppercase" }}>
                  Detected from your viewing history
                </p>
                <p style={{ fontFamily: F.sans, fontSize: "15px", fontWeight: 600, color: C.text, marginBottom: "20px" }}>
                  What world do you want to create in?
                </p>
                {Object.entries(trees).map(([name, data]) => (
                  <button key={name} onClick={() => setNiche(name)} style={{
                    width: "100%", padding: "14px 16px", marginBottom: "8px",
                    background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.08)",
                    borderRadius: "12px", cursor: "pointer", display: "flex", alignItems: "center", gap: "12px",
                    transition: "all 0.2s",
                  }}
                  onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,255,255,0.1)"; e.currentTarget.style.borderColor = "rgba(255,255,255,0.15)"; }}
                  onMouseLeave={e => { e.currentTarget.style.background = "rgba(255,255,255,0.05)"; e.currentTarget.style.borderColor = "rgba(255,255,255,0.08)"; }}
                  >
                    <span style={{ fontSize: "22px" }}>{data.icon}</span>
                    <div style={{ textAlign: "left" }}>
                      <div style={{ fontFamily: F.sans, fontSize: "14px", fontWeight: 600, color: C.text }}>{name}</div>
                      <div style={{ fontFamily: F.sans, fontSize: "11px", color: C.dim }}>{data.detected}</div>
                    </div>
                  </button>
                ))}
              </>
            )}

            {niche && !done && tree && (
              <>
                {/* Progress */}
                <div style={{ display: "flex", gap: "4px", marginBottom: "20px" }}>
                  {tree.questions.map((_, i) => (
                    <div key={i} style={{
                      flex: 1, height: "3px", borderRadius: "2px",
                      background: i <= qIdx ? C.red : "rgba(255,255,255,0.1)",
                      transition: "background 0.3s",
                    }} />
                  ))}
                </div>
                <p style={{ fontFamily: F.mono, fontSize: "9px", color: C.dim, letterSpacing: "0.1em", marginBottom: "4px", textTransform: "uppercase" }}>
                  {qIdx + 1} of {tree.questions.length}
                </p>
                <p style={{ fontFamily: F.sans, fontSize: "17px", fontWeight: 600, color: C.text, marginBottom: "20px", lineHeight: 1.35 }}>
                  {tree.questions[qIdx].q}
                </p>
                {tree.questions[qIdx].opts.map((opt, i) => (
                  <button key={i} onClick={() => pick(opt)} style={{
                    width: "100%", padding: "13px 16px", marginBottom: "8px",
                    background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.08)",
                    borderRadius: "12px", cursor: "pointer", textAlign: "left",
                    fontFamily: F.sans, fontSize: "14px", color: C.text,
                    transition: "all 0.15s",
                  }}
                  onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,0,0,0.12)"; e.currentTarget.style.borderColor = C.redBorder; }}
                  onMouseLeave={e => { e.currentTarget.style.background = "rgba(255,255,255,0.05)"; e.currentTarget.style.borderColor = "rgba(255,255,255,0.08)"; }}
                  >
                    {opt}
                  </button>
                ))}
                <button onClick={reset} style={{ fontFamily: F.sans, fontSize: "12px", color: C.dim, background: "none", border: "none", cursor: "pointer", marginTop: "12px", padding: "4px 0" }}>
                  ← Start over
                </button>
              </>
            )}

            {done && (
              <div style={{ animation: "fadeUp 0.4s ease" }}>
                <Pill color={C.green} bg={C.greenDim}>YOUR PROMPT — ASSEMBLED FROM YOUR CHOICES</Pill>
                <div style={{
                  marginTop: "16px", padding: "16px", background: "rgba(255,255,255,0.05)",
                  borderRadius: "12px", border: "1px solid rgba(255,255,255,0.1)",
                }}>
                  <p style={{ fontFamily: F.sans, fontSize: "15px", color: C.text, lineHeight: 1.55, fontWeight: 500 }}>
                    {tree.build(ans)}
                  </p>
                </div>

                <div style={{ margin: "20px 0 12px", display: "flex", gap: "8px" }}>
                  {ans.map((a, i) => (
                    <span key={i} style={{ fontFamily: F.mono, fontSize: "9px", color: C.sub, background: "rgba(255,255,255,0.06)", padding: "4px 8px", borderRadius: "4px", fontWeight: 500 }}>
                      Q{i+1}: {a.length > 22 ? a.slice(0,22) + "…" : a}
                    </span>
                  ))}
                </div>

                <div style={{ marginTop: "20px", padding: "14px", background: C.redGlow, borderRadius: "10px", border: `1px solid ${C.redBorder}` }}>
                  <p style={{ fontFamily: F.mono, fontSize: "9px", color: C.red, letterSpacing: "0.1em", marginBottom: "6px" }}>YOUTUBE CURRENTLY SUGGESTS</p>
                  <p style={{ fontFamily: F.sans, fontSize: "13px", color: C.sub }}>"{tree.generic}"</p>
                </div>

                <div style={{ display: "flex", gap: "8px", marginTop: "20px" }}>
                  <button onClick={reset} style={{
                    flex: 1, padding: "12px", borderRadius: "24px",
                    background: "rgba(255,255,255,0.08)", border: "1px solid rgba(255,255,255,0.12)",
                    fontFamily: F.sans, fontSize: "13px", color: C.text, cursor: "pointer",
                  }}>Try another niche</button>
                  <button style={{
                    flex: 1, padding: "12px", borderRadius: "24px",
                    background: C.red, border: "none",
                    fontFamily: F.sans, fontSize: "13px", fontWeight: 600, color: C.text, cursor: "pointer",
                  }}>Create with this →</button>
                </div>
              </div>
            )}
          </div>

          {/* Bottom bar - Shorts camera style */}
          <div style={{
            position: "absolute", bottom: 0, left: 0, right: 0,
            padding: "12px 20px 24px", display: "flex", justifyContent: "space-around", alignItems: "center",
            background: "linear-gradient(transparent, rgba(0,0,0,0.9))",
          }}>
            {["🎭 Effects", "📷 Upload", "♫ Sound"].map(item => (
              <span key={item} style={{ fontFamily: F.sans, fontSize: "10px", color: C.dim }}>{item}</span>
            ))}
          </div>
        </div>

        {/* Right side - annotation */}
        <div className="demo-annotations" style={{ flex: 1, paddingTop: "40px", maxWidth: "400px" }}>
          <h3 style={{ fontFamily: F.sans, fontSize: "18px", fontWeight: 600, color: C.text, marginBottom: "16px" }}>
            What's different
          </h3>
          {[
            { label: "No blank page", desc: "Every step is a tap, not a type. The user never faces an empty field." },
            { label: "Each tap adds commitment", desc: "A blank field subtracts emotional energy. Each disambiguation tap adds it back by narrowing toward something specific." },
            { label: "Every prompt is unique", desc: "Two users picking the same niche get different prompts, because they have different takes." },
            { label: "30 seconds", desc: "Four questions, tappable options. Faster than typing a prompt from scratch, and the output is more specific." },
            { label: "Ownership", desc: "The user chose every component. The prompt feels like theirs, not a suggestion they settled for." },
          ].map(item => (
            <div key={item.label} style={{ marginBottom: "20px" }}>
              <div style={{ fontFamily: F.sans, fontSize: "14px", fontWeight: 600, color: C.text, marginBottom: "4px" }}>{item.label}</div>
              <p style={{ fontFamily: F.sans, fontSize: "13px", color: C.sub, lineHeight: 1.6 }}>{item.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

